   102‚Üífunction getRedisConfig() {
   103‚Üí  return {
   104‚Üí    host: process.env['REDIS_HOST'] ?? 'localhost',
   105‚Üí    port: parseInt(process.env['REDIS_PORT'] ?? '6379', 10),
   106‚Üí    password: process.env['REDIS_PASSWORD'],
   107‚Üí    maxRetriesPerRequest: null as null, // Required for BullMQ
   108‚Üí  };
   109‚Üí}
   110‚Üí
   111‚Üí// =============================================================================
   112‚Üí// Base Worker Types
   113‚Üí// =============================================================================
   114‚Üí
   115‚Üí/**
   116‚Üí * Job context passed to processor functions
   117‚Üí */
   118‚Üíexport interface WorkerJobContext<T extends JobData = JobData> {
   119‚Üí  /** Job ID */
   120‚Üí  id: string;
   121‚Üí  /** Job name */
   122‚Üí  name: string;
   123‚Üí  /** Job data payload */
   124‚Üí  data: T;
   125‚Üí  /** Job attempt number (1-based) */
   126‚Üí  attemptsMade: number;
   127‚Üí  /** Update job progress (0-100) */
   128‚Üí  updateProgress: (progress: number | object) => Promise<void>;
   129‚Üí  /** Add log message to job */
   130‚Üí  log: (message: string) => Promise<void>;
   131‚Üí}
   132‚Üí
   133‚Üí/**
   134‚Üí * Worker processor function signature
   135‚Üí */
   136‚Üíexport type WorkerProcessor<T extends JobData = JobData, R = unknown> = (
   137‚Üí  context: WorkerJobContext<T>
   138‚Üí) => Promise<R>;
   139‚Üí
   140‚Üí/**
   141‚Üí * Worker registration result
   142‚Üí */
   143‚Üíexport interface RegisteredWorker {
   144‚Üí  /** Worker instance */
   145‚Üí  worker: Worker;
   146‚Üí  /** Queue name */
   147‚Üí  queueName: QueueName;
   148‚Üí  /** Worker description */
   149‚Üí  description: string;
   150‚Üí  /** Graceful shutdown function */
   151‚Üí  close: () => Promise<void>;
   152‚Üí}
   153‚Üí
   154‚Üí// =============================================================================
   155‚Üí// Worker Factory
   156‚Üí// =============================================================================
   157‚Üí
   158‚Üíconst registeredWorkers: Map<QueueName, RegisteredWorker> = new Map();
   159‚Üí
   160‚Üí/**
   161‚Üí * Create and register a worker for a queue
   162‚Üí *
   163‚Üí * @param queueKey - Key from QUEUE_NAMES (e.g., 'INGESTION')
   164‚Üí * @param processor - Function to process jobs
   165‚Üí * @param options - Optional worker configuration overrides
   166‚Üí * @returns Registered worker instance
   167‚Üí */
   168‚Üíexport function registerWorker<T extends JobData = JobData, R = unknown>(
   169‚Üí  queueKey: keyof typeof QUEUE_NAMES,
   170‚Üí  processor: WorkerProcessor<T, R>,
   171‚Üí  options?: Partial<WorkerOptions>
   172‚Üí): RegisteredWorker {
   173‚Üí  const queueName = QUEUE_NAMES[queueKey];
   174‚Üí  const config = WORKER_CONFIGS[queueKey];
   175‚Üí
   176‚Üí  // Check if already registered
   177‚Üí  if (registeredWorkers.has(queueName)) {
   178‚Üí    const existing = registeredWorkers.get(queueName)!;
   179‚Üí    logger.warn({ queueName }, 'Worker already registered, returning existing');
   180‚Üí    return existing;
   181‚Üí  }
   182‚Üí
   183‚Üí  const workerOptions: WorkerOptions = {
   184‚Üí    connection: getRedisConfig(),
   185‚Üí    concurrency: config.concurrency,
   186‚Üí    lockDuration: config.lockDuration,
   187‚Üí    lockRenewTime: Math.floor(config.lockDuration / 2),
   188‚Üí    ...options,
   189‚Üí  };
   190‚Üí
   191‚Üí  const worker = new Worker<T, R>(
   192‚Üí    queueName,
   193‚Üí    async (job: Job<T>) => {
   194‚Üí      const startTime = Date.now();
   195‚Üí      const jobLogger = logger.child({
   196‚Üí        queueName,
   197‚Üí        jobId: job.id,
   198‚Üí        jobName: job.name,
   199‚Üí        attemptsMade: job.attemptsMade,
   200‚Üí      });
   201‚Üí
   202‚Üí      jobLogger.info('Starting job processing');
   203‚Üí      workerMetrics.queueJobStarted.labels(queueName).inc();
   204‚Üí
   205‚Üí      try {
   206‚Üí        const result = await withSpan(
   207‚Üí          `worker.${queueKey.toLowerCase()}`,
   208‚Üí          async () => {
   209‚Üí            const workerContext: WorkerJobContext<T> = {
   210‚Üí              id: job.id ?? 'unknown',
   211‚Üí              name: job.name,
   212‚Üí              data: job.data,
   213‚Üí              attemptsMade: job.attemptsMade,
   214‚Üí              updateProgress: async (progress) => {
   215‚Üí                await job.updateProgress(progress);
   216‚Üí              },
   217‚Üí              log: async (message) => {
   218‚Üí                await job.log(message);
   219‚Üí                jobLogger.debug({ message }, 'Job log');
   220‚Üí              },
   221‚Üí            };
   222‚Üí
   223‚Üí            return processor(workerContext);
   224‚Üí          },
   225‚Üí          {
   226‚Üí            attributes: {
   227‚Üí              queueName,
   228‚Üí              jobId: job.id ?? 'unknown',
   229‚Üí              jobName: job.name,
   230‚Üí            },
   231‚Üí          }
   232‚Üí        );
   233‚Üí
   234‚Üí        const durationMs = Date.now() - startTime;
   235‚Üí        jobLogger.info({ durationMs }, 'Job completed successfully');
   236‚Üí        workerMetrics.queueJobCompleted.labels(queueName).inc();
   237‚Üí        workerMetrics.queueJobDuration.labels(queueName).observe(durationMs / 1000);
   238‚Üí
   239‚Üí        return result;
   240‚Üí      } catch (error) {
   241‚Üí        const durationMs = Date.now() - startTime;
   242‚Üí        const mmsError = toMmsError(error);
   243‚Üí
   244‚Üí        jobLogger.error(
   245‚Üí          {
   246‚Üí            error: mmsError.message,
   247‚Üí            code: mmsError.code,
   248‚Üí            durationMs,
   249‚Üí          },
   250‚Üí          'Job failed'
   251‚Üí        );
   252‚Üí
   253‚Üí        workerMetrics.queueJobFailed.labels(queueName).inc();
   254‚Üí
   255‚Üí        throw new QueueError(`Job ${job.id} failed: ${mmsError.message}`, {
   256‚Üí          queueName,
   257‚Üí          jobId: job.id,
   258‚Üí          context: {
   259‚Üí            attemptsMade: job.attemptsMade,
   260‚Üí            originalError: mmsError.code,
   261‚Üí          },
   262‚Üí        });
   263‚Üí      }
   264‚Üí    },
   265‚Üí    workerOptions
   266‚Üí  );
   267‚Üí
   268‚Üí  // Register event handlers
   269‚Üí  worker.on('ready', () => {
   270‚Üí    logger.info({ queueName, concurrency: workerOptions.concurrency }, 'Worker ready');
   271‚Üí  });
   272‚Üí
   273‚Üí  worker.on('error', (error) => {
   274‚Üí    logger.error({ queueName, error: error.message }, 'Worker error');
   275‚Üí  });
   276‚Üí
   277‚Üí  worker.on('stalled', (jobId) => {
   278‚Üí    logger.warn({ queueName, jobId }, 'Job stalled');
   279‚Üí    workerMetrics.queueJobFailed.labels(queueName).inc();
   280‚Üí  });
   281‚Üí
   282‚Üí  const registeredWorker: RegisteredWorker = {
   283‚Üí    worker,
   284‚Üí    queueName,
   285‚Üí    description: config.description,
   286‚Üí    close: async () => {
   287‚Üí      logger.info({ queueName }, 'Closing worker');
   288‚Üí      await worker.close();
   289‚Üí      registeredWorkers.delete(queueName);
   290‚Üí    },
   291‚Üí  };
   292‚Üí
   293‚Üí  registeredWorkers.set(queueName, registeredWorker);
   294‚Üí  logger.info({ queueName, description: config.description }, 'Worker registered');
   295‚Üí
   296‚Üí  return registeredWorker;
   297‚Üí}
   298‚Üí
   299‚Üí/**
   300‚Üí * Get a registered worker by queue key
   301‚Üí */
   302‚Üíexport function getWorker(queueKey: keyof typeof QUEUE_NAMES): RegisteredWorker | undefined {
   303‚Üí  return registeredWorkers.get(QUEUE_NAMES[queueKey]);
   304‚Üí}
   305‚Üí
   306‚Üí/**
   307‚Üí * Get all registered workers
   308‚Üí */
   309‚Üíexport function getAllWorkers(): RegisteredWorker[] {
   310‚Üí  return Array.from(registeredWorkers.values());
   311‚Üí}
   312‚Üí
   313‚Üí/**
   314‚Üí * Close all registered workers gracefully
   315‚Üí */
   316‚Üíexport async function closeAllWorkers(): Promise<void> {
   317‚Üí  logger.info({ count: registeredWorkers.size }, 'Closing all workers');
   318‚Üí
   319‚Üí  const closePromises: Promise<void>[] = [];
   320‚Üí  for (const worker of registeredWorkers.values()) {
   321‚Üí    closePromises.push(worker.close());
   322‚Üí  }
   323‚Üí
   324‚Üí  await Promise.all(closePromises);
   325‚Üí  logger.info('All workers closed');
   326‚Üí}
   327‚Üí
   328‚Üí// =============================================================================
   329‚Üí// Health Check
   330‚Üí// =============================================================================
   331‚Üí
   332‚Üí/**
   333‚Üí * Worker health status
   334‚Üí */
   335‚Üíexport interface WorkerHealth {
   336‚Üí  queueName: QueueName;
   337‚Üí  description: string;
   338‚Üí  isRunning: boolean;
   339‚Üí  isPaused: boolean;
   340‚Üí}
   341‚Üí
   342‚Üí/**
   343‚Üí * Get health status of all workers
   344‚Üí */
   345‚Üíexport async function getWorkersHealth(): Promise<WorkerHealth[]> {
   346‚Üí  const health: WorkerHealth[] = [];
   347‚Üí
   348‚Üí  for (const [queueName, registered] of registeredWorkers.entries()) {
   349‚Üí    health.push({
   350‚Üí      queueName,
   351‚Üí      description: registered.description,
   352‚Üí      isRunning: registered.worker.isRunning(),
   353‚Üí      isPaused: registered.worker.isPaused(),
   354‚Üí    });
   355‚Üí  }
   356‚Üí
   357‚Üí  return health;
   358‚Üí}
   359‚Üí
   360‚Üí// =============================================================================
   361‚Üí// Re-exports for convenience
   362‚Üí// =============================================================================
   363‚Üí
   364‚Üíexport {
   365‚Üí  QUEUE_NAMES,
   366‚Üí  type QueueName,
   367‚Üí  type JobData,
   368‚Üí  type IngestionJobData,
   369‚Üí  type TacticalSchedulerJobData,
   370‚Üí  type StrategicPlannerJobData,
   371‚Üí  type OptimizerJobData,
   372‚Üí  type ManhourLevelingJobData,
   373‚Üí  type DriftMonitorJobData,
   374‚Üí  type NotificationJobData,
   375‚Üí  type ReportJobData,
   376‚Üí  type MaximoSyncJobData,
   377‚Üí} from '../lib/queue';
   378‚Üí
   379‚Üíexport { addJob, addBulkJobs, getJob, getQueueStats, getQueue } from '../lib/queue';
   380‚Üí
   381‚Üí// =============================================================================
   382‚Üí// Worker Processors
   383‚Üí// =============================================================================
   384‚Üí
   385‚Üíexport { processOptimizerJob } from './processors/optimizer';
   386‚Üíexport { processDriftMonitorJob } from './processors/drift-monitor';
   387‚Üíexport { processIngestionJob } from './processors/ingestion';
   388‚Üíexport { processMaximoSyncJob } from './processors/maximo-sync';
   389‚Üíexport { processStrategicPlannerJob } from './processors/strategic-planner';
   390‚Üíexport { processNotificationJob } from './processors/notification';
   391‚Üíexport { processTacticalSchedulerJob } from './processors/tactical-scheduler';
   392‚Üíexport { processManhourLevelingJob } from './processors/manhour-leveling';
   393‚Üíexport { processReportJob, type ReportResult } from './processors/report';
   394‚Üí
