    11‚Üí * 4. Process meter events (resets, replacements)
    12‚Üí * 5. Store results and update train mileage
    13‚Üí *
    14‚Üí * @see specs/004-domain-services.md Section 4.2.3
    15‚Üí */
    16‚Üí
    17‚Üíimport { logger } from '../../lib/logging/logger';
    18‚Üíimport { withSpan } from '../../lib/tracing';
    19‚Üíimport { type WorkerJobContext } from '../index';
    20‚Üíimport { type IngestionJobData } from '../../lib/queue';
    21‚Üíimport { getIngestionService, type IngestionResult } from '../../services';
    22‚Üíimport { ingestionMetrics, recordIngestionComplete } from '../../lib/metrics';
    23‚Üí
    24‚Üí// =============================================================================
