/**
 * MMS Strategic Planner Worker Processor
 *
 * BullMQ job processor for long-term strategic planning.
 * Generates 1-10 year PM plans using genetic algorithms.
 *
 * Job Flow:
 * 1. Receive StrategicPlannerJobData from queue
 * 2. Load fleet state and PM types
 * 3. Project PM requirements over horizon
 * 4. Generate constraint envelopes
 * 5. Run genetic algorithm optimization
 * 6. Validate and repair plan if needed
 * 7. Store results and broadcast via WebSocket
 *
 * @see specs/004-domain-services.md Section 4.5
 */

import { logger } from '../../lib/logging/logger';
import { withSpan } from '../../lib/tracing';
import { type WorkerJobContext } from '../index';
import { type StrategicPlannerJobData } from '../../lib/queue';
import {
  getStrategicPlannerService,
  type StrategicPlanResult,
} from '../../services';

// =============================================================================
// Worker Configuration
// =============================================================================

const log = logger.child({ worker: 'strategic-planner' });

// =============================================================================
// Job Processor
// =============================================================================

/**
 * Process strategic planner job
 *
 * Generates long-term strategic PM plan using genetic algorithm.
 * This is a long-running operation that streams progress updates.
 */
export async function processStrategicPlannerJob(
  context: WorkerJobContext<StrategicPlannerJobData>
): Promise<StrategicPlanResult> {
  return withSpan('worker.strategic_planner.process', async (span) => {
    const { id, data } = context;
    const { fleetId, horizonYears, populationSize, generations } = data;

    span.setAttribute('jobId', id);
    span.setAttribute('horizonYears', horizonYears ?? 10);
    span.setAttribute('populationSize', populationSize ?? 100);
    span.setAttribute('generations', generations ?? 500);
    if (fleetId) {
      span.setAttribute('fleetId', fleetId);
    }

    log.info(
      {
        jobId: id,
        fleetId: fleetId ?? 'all',
        horizonYears: horizonYears ?? 10,
        populationSize: populationSize ?? 100,
        generations: generations ?? 500,
      },
      'Processing strategic planner job'
    );

    // Update progress: initializing
    await context.updateProgress({ stage: 'INITIALIZING', percent: 0 });
    await context.log('Initializing strategic planning');

    // Get strategic planner service
    const plannerService = getStrategicPlannerService();

    // Run strategic planning with progress callback
    const result = await plannerService.generatePlan({
      horizonYears,
      fleetId,
      populationSize,
      generations,
      onProgress: async (progress) => {
        await context.updateProgress({
          stage: progress.stage,
          percent: progress.percent,
          generation: progress.generation,
          fitness: progress.fitness,
        });

        if (progress.message) {
          await context.log(progress.message);
        }

        // Log every 100 generations
        if (progress.generation !== undefined && progress.generation % 100 === 0) {
          log.debug(
            {
              jobId: id,
              generation: progress.generation,
              fitness: progress.fitness,
              percent: progress.percent,
            },
            'Strategic planning progress'
          );
        }
      },
    });

    // Update progress: complete
    await context.updateProgress({ stage: 'COMPLETE', percent: 100 });

    log.info(
      {
        jobId: id,
        planId: result.planId,
        totalPMs: result.metrics.totalPMs,
        totalHours: result.metrics.totalHours,
        complianceRate: result.metrics.complianceRate,
        bowWaveRisk: result.metrics.bowWaveRisk,
        validationScore: result.validation.score,
        violations: result.validation.violations.length,
        warnings: result.validation.warnings.length,
      },
      'Strategic planning complete'
    );

    await context.log(
      `Plan generated: ${result.metrics.totalPMs} PMs over ${result.config.horizonYears} years, ` +
        `${result.metrics.totalHours.toFixed(0)} total hours, ` +
        `validation score: ${result.validation.score.toFixed(1)}/100`
    );

    // Log any violations
    for (const violation of result.validation.violations) {
      log.warn(
        {
          jobId: id,
          type: violation.type,
          quarter: violation.quarter,
          severity: violation.severity,
        },
        `Plan violation: ${violation.description}`
      );
    }

    return result;
  });
}

