/**
 * MMS Drift Monitor Worker Processor
 *
 * BullMQ job processor for drift analysis between baselines and current state.
 * Runs nightly to detect mileage drift, PM schedule drift, and generate alerts.
 *
 * Job Flow:
 * 1. Receive DriftMonitorJobData from queue
 * 2. Fetch baseline and current train data
 * 3. Run drift analysis via DriftMonitorService
 * 4. Generate alerts if thresholds exceeded
 * 5. Store results and broadcast via WebSocket
 *
 * @see specs/004-domain-services.md Section 4.8
 */

import { logger } from '../../lib/logging/logger';
import { withSpan } from '../../lib/tracing';
import { type WorkerJobContext } from '../index';
import { type DriftMonitorJobData } from '../../lib/queue';
import { getDriftMonitorService, type DriftAnalysisResult } from '../../services';

// =============================================================================
// Worker Configuration
// =============================================================================

const log = logger.child({ worker: 'drift-monitor' });

// =============================================================================
// Job Processor
// =============================================================================

/**
 * Process drift monitor job
 *
 * Runs drift analysis comparing current fleet state against published baseline.
 * Generates alerts when drift thresholds are exceeded.
 */
export async function processDriftMonitorJob(
  context: WorkerJobContext<DriftMonitorJobData>
): Promise<DriftAnalysisResult> {
  return withSpan('worker.drift_monitor.process', async (span) => {
    const { id, data } = context;
    const { baselineId, trainIds } = data;

    span.setAttribute('jobId', id);
    span.setAttribute('baselineId', baselineId);
    span.setAttribute('hasTrainFilter', !!trainIds);
    if (trainIds) {
      span.setAttribute('trainCount', trainIds.length);
    }

    log.info(
      { jobId: id, baselineId, trainIds: trainIds?.length ?? 'all' },
      'Processing drift monitor job'
    );

    // Update progress: initializing
    await context.updateProgress({ stage: 'INITIALIZING', percent: 10 });
    await context.log('Initializing drift analysis');

    // Get drift monitor service
    const driftService = getDriftMonitorService();

    // Update progress: analyzing
    await context.updateProgress({ stage: 'ANALYZING', percent: 30 });
    await context.log(`Running drift analysis for baseline ${baselineId}`);

    // Run drift analysis
    // The service's runDriftAnalysis handles:
    // - Fetching baseline data
    // - Comparing against current fleet state
    // - Calculating mileage and PM drift
    // - Generating alerts based on thresholds
    const result = await driftService.runDriftAnalysis();

    // Update progress: finalizing
    await context.updateProgress({ stage: 'FINALIZING', percent: 90 });

    if (result.skipped) {
      log.info({ jobId: id, reason: result.reason }, 'Drift analysis skipped');
      await context.log(`Analysis skipped: ${result.reason}`);
    } else {
      const { summary, trainAnalyses, alerts } = result;

      log.info(
        {
          jobId: id,
          totalTrains: summary.totalTrains,
          trainsWithDrift: summary.trainsWithDrift,
          trainsRequiringReplan: summary.trainsRequiringReplan,
          alertCount: alerts.length,
        },
        'Drift analysis complete'
      );

      await context.log(
        `Analyzed ${summary.totalTrains} trains, ${summary.trainsWithDrift} with drift, ` +
          `${summary.trainsRequiringReplan} requiring replan, ${alerts.length} alerts generated`
      );

      // Log high-severity alerts
      const criticalAlerts = alerts.filter((a) => a.severity === 'CRITICAL');
      if (criticalAlerts.length > 0) {
        log.warn(
          { jobId: id, criticalAlerts: criticalAlerts.length },
          'Critical drift alerts detected'
        );

        for (const alert of criticalAlerts) {
          await context.log(`CRITICAL: ${alert.message}`);
        }
      }

      // Record metrics for Prometheus
      span.setAttribute('drift.totalTrains', summary.totalTrains);
      span.setAttribute('drift.trainsWithDrift', summary.trainsWithDrift);
      span.setAttribute('drift.trainsRequiringReplan', summary.trainsRequiringReplan);
      span.setAttribute('drift.avgFleetDriftPct', summary.avgFleetDriftPct);
      span.setAttribute('drift.alertCount', alerts.length);

      // Filter by trainIds if specified
      if (trainIds && trainIds.length > 0) {
        const filteredAnalyses = trainAnalyses.filter((a) =>
          trainIds.includes(a.trainId)
        );
        log.debug(
          {
            jobId: id,
            original: trainAnalyses.length,
            filtered: filteredAnalyses.length,
          },
          'Filtered train analyses by trainIds'
        );
      }
    }

    // Update progress: complete
    await context.updateProgress({ stage: 'COMPLETE', percent: 100 });

    return result;
  });
}

/**
 * Register the drift monitor worker
 */
export function registerDriftMonitorWorker(): void {
  log.info('Drift monitor worker processor available for registration');
}

