     2‚Üí * MMS Notification Worker Processor
     3‚Üí *
     4‚Üí * BullMQ job processor for email notification delivery and digest processing.
     5‚Üí * Handles immediate email sending and scheduled digest batch delivery.
     6‚Üí *
     7‚Üí * Job Types (by name):
     8‚Üí * - send-email: Immediate email delivery
     9‚Üí * - process-digests: Process pending digest batches
    10‚Üí * - retry-failed: Retry failed notifications
    11‚Üí * - cleanup: Clean up old notification logs
    12‚Üí *
    13‚Üí * @see specs/004-domain-services.md Section 4.12
    14‚Üí * @see specs/007-integration.md Section 7.5
    15‚Üí */
    16‚Üí
    17‚Üíimport { logger } from '../../lib/logging/logger';
    18‚Üíimport { withSpan } from '../../lib/tracing';
    19‚Üíimport { type WorkerJobContext } from '../index';
    20‚Üíimport { type NotificationJobData } from '../../lib/queue';
    21‚Üíimport { getNotificationService } from '../../services/notification';
    22‚Üíimport { notificationMetrics } from '../../lib/metrics';
    23‚Üí
    24‚Üí// =============================================================================
    25‚Üí// Worker Configuration
    26‚Üí// =============================================================================
    27‚Üí
    28‚Üíconst log = logger.child({ worker: 'notification' });
    29‚Üí
    30‚Üí// =============================================================================
    31‚Üí// Job Processor
    32‚Üí// =============================================================================
    33‚Üí
    34‚Üí/**
    35‚Üí * Process notification job
    36‚Üí *
    37‚Üí * Routes to appropriate handler based on job name.
    38‚Üí * All job data must conform to NotificationJobData.
    39‚Üí */
