    41‚Üí  context: WorkerJobContext<NotificationJobData>
    42‚Üí): Promise<unknown> {
    43‚Üí  return withSpan('worker.notification.process', async (span) => {
    44‚Üí    const { id, name, data } = context;
    45‚Üí
    46‚Üí    span.setAttribute('jobId', id ?? 'unknown');
    47‚Üí    span.setAttribute('jobName', name);
    48‚Üí
    49‚Üí    log.info({ jobId: id, jobName: name }, 'Processing notification job');
    50‚Üí
    51‚Üí    // Update progress: starting
    52‚Üí    await context.updateProgress({ stage: 'STARTING', percent: 10 });
    53‚Üí
    54‚Üí    try {
    55‚Üí      let result: unknown;
    56‚Üí
    57‚Üí      switch (name) {
    58‚Üí        case 'send-email':
    59‚Üí          result = await handleSendEmail(context);
