    73‚Üí
    74‚Üí        default:
    75‚Üí          // Treat as generic email send if data has recipients
    76‚Üí          if ('recipients' in data && Array.isArray(data.recipients)) {
    77‚Üí            result = await handleSendEmail(context);
    78‚Üí          } else {
    79‚Üí            throw new Error(`Unknown notification job type: ${name}`);
    80‚Üí          }
    81‚Üí      }
    82‚Üí
    83‚Üí      // Update progress: complete
    84‚Üí      await context.updateProgress({ stage: 'COMPLETE', percent: 100 });
    85‚Üí
    86‚Üí      return result;
    87‚Üí    } catch (error) {
    88‚Üí      log.error({ jobId: id, jobName: name, error }, 'Notification job failed');
    89‚Üí      throw error;
    90‚Üí    }
    91‚Üí  });
    92‚Üí}
    93‚Üí
    94‚Üí// =============================================================================
    95‚Üí// Job Handlers
    96‚Üí// =============================================================================
    97‚Üí
    98‚Üí/**
    99‚Üí * Handle send-email job
   100‚Üí *
   101‚Üí * Delivers a single email notification immediately.
   102‚Üí */
   103‚Üíasync function handleSendEmail(
   104‚Üí  context: WorkerJobContext<NotificationJobData>
   105‚Üí): Promise<{ success: boolean; messageId?: string; error?: string }> {
   106‚Üí  const { data } = context;
   107‚Üí  const { template, recipients, data: emailData } = data;
