/**
 * MMS Notification Worker Processor
 *
 * BullMQ job processor for email notification delivery and digest processing.
 * Handles immediate email sending and scheduled digest batch delivery.
 *
 * Job Types (by name):
 * - send-email: Immediate email delivery
 * - process-digests: Process pending digest batches
 * - retry-failed: Retry failed notifications
 * - cleanup: Clean up old notification logs
 *
 * @see specs/004-domain-services.md Section 4.12
 * @see specs/007-integration.md Section 7.5
 */

import { logger } from '../../lib/logging/logger';
import { withSpan } from '../../lib/tracing';
import { type WorkerJobContext } from '../index';
import { type NotificationJobData } from '../../lib/queue';
import { getNotificationService } from '../../services/notification';
import { notificationMetrics } from '../../lib/metrics';

// =============================================================================
// Worker Configuration
// =============================================================================

const log = logger.child({ worker: 'notification' });

// =============================================================================
// Job Processor
// =============================================================================

/**
 * Process notification job
 *
 * Routes to appropriate handler based on job name.
 * All job data must conform to NotificationJobData.
 */
export async function processNotificationJob(
  context: WorkerJobContext<NotificationJobData>
): Promise<unknown> {
  return withSpan('worker.notification.process', async (span) => {
    const { id, name, data } = context;

    span.setAttribute('jobId', id ?? 'unknown');
    span.setAttribute('jobName', name);

    log.info({ jobId: id, jobName: name }, 'Processing notification job');

    // Update progress: starting
    await context.updateProgress({ stage: 'STARTING', percent: 10 });

    try {
      let result: unknown;

      switch (name) {
        case 'send-email':
          result = await handleSendEmail(context);
          break;

        case 'process-digests':
          result = await handleProcessDigests(context);
          break;

        case 'retry-failed':
          result = await handleRetryFailed(context);
          break;

        case 'cleanup':
          result = await handleCleanup(context);
          break;

        default:
          // Treat as generic email send if data has recipients
          if ('recipients' in data && Array.isArray(data.recipients)) {
            result = await handleSendEmail(context);
          } else {
            throw new Error(`Unknown notification job type: ${name}`);
          }
      }

      // Update progress: complete
      await context.updateProgress({ stage: 'COMPLETE', percent: 100 });

      return result;
    } catch (error) {
      log.error({ jobId: id, jobName: name, error }, 'Notification job failed');
      throw error;
    }
  });
}

// =============================================================================
// Job Handlers
// =============================================================================

/**
 * Handle send-email job
 *
 * Delivers a single email notification immediately.
 */
async function handleSendEmail(
  context: WorkerJobContext<NotificationJobData>
): Promise<{ success: boolean; messageId?: string; error?: string }> {
  const { data } = context;
  const { template, recipients, data: emailData } = data;
  const notificationLogId = (emailData as Record<string, unknown>)['notificationLogId'] as string;

  await context.log(`Sending email to ${recipients.length} recipient(s)`);
  await context.updateProgress({ stage: 'SENDING', percent: 50 });

  const notificationService = getNotificationService();

  // Send to each recipient
  const results: Array<{ success: boolean; messageId?: string; error?: string }> = [];

  for (const recipient of recipients) {
    const result = await notificationService.deliverEmail(
      notificationLogId,
      template,
      recipient,
      emailData as Record<string, unknown>
    );
    results.push(result);
  }

  // Check overall success
  const succeeded = results.filter((r) => r.success).length;
  const failed = results.filter((r) => !r.success).length;

  await context.log(`Email delivery: ${succeeded} succeeded, ${failed} failed`);

  if (failed > 0) {
    const firstError = results.find((r) => !r.success)?.error;
    return {
      success: succeeded > 0,
      error: failed === recipients.length ? firstError : `${failed}/${recipients.length} failed`,
    };
  }

  return {
    success: true,
    messageId: results[0]?.messageId,
  };
}

/**
 * Handle process-digests job
 *
 * Processes pending digest batches that are due for delivery.
 * Typically scheduled to run hourly.
 */
async function handleProcessDigests(
  context: WorkerJobContext<NotificationJobData>
): Promise<{ processed: number; sent: number; failed: number }> {
  await context.log('Processing pending digest batches');
  await context.updateProgress({ stage: 'PROCESSING_DIGESTS', percent: 30 });

  const notificationService = getNotificationService();
  const result = await notificationService.processDigestBatches();

  await context.log(
    `Digest processing: ${result.processed} processed, ${result.sent} sent, ${result.failed} failed`
  );

  // Update metrics
  notificationMetrics.digestBatchesProcessed.inc({ status: 'sent' }, result.sent);
  notificationMetrics.digestBatchesProcessed.inc({ status: 'failed' }, result.failed);

  return result;
}

/**
 * Handle retry-failed job
 *
 * Retries failed notifications up to max retry count.
 * Typically scheduled to run every 15 minutes.
 */
async function handleRetryFailed(
  context: WorkerJobContext<NotificationJobData>
): Promise<{ retried: number; succeeded: number }> {
  const { data } = context;
  const maxRetries = (data.data as Record<string, unknown>)['maxRetries'] as number ?? 3;

  await context.log(`Retrying failed notifications (max retries: ${maxRetries})`);
  await context.updateProgress({ stage: 'RETRYING', percent: 30 });

  const notificationService = getNotificationService();
  const result = await notificationService.retryFailedNotifications(maxRetries);

  await context.log(`Retry results: ${result.retried} retried, ${result.succeeded} succeeded`);

  return result;
}

/**
 * Handle cleanup job
 *
 * Cleans up old notification logs based on retention policy.
 * Typically scheduled to run daily.
 */
async function handleCleanup(
  context: WorkerJobContext<NotificationJobData>
): Promise<{ deleted: number }> {
  const { data } = context;
  const retentionDays = (data.data as Record<string, unknown>)['retentionDays'] as number ?? 90;

  await context.log(`Cleaning up notification logs older than ${retentionDays} days`);
  await context.updateProgress({ stage: 'CLEANUP', percent: 30 });

  const notificationService = getNotificationService();
  const deleted = await notificationService.cleanupOldLogs(retentionDays);

  await context.log(`Cleanup: ${deleted} old logs deleted`);

  return { deleted };
}

/**
 * Register the notification worker
 */
export function registerNotificationWorker(): void {
  log.info('Notification worker processor available for registration');
}

