     1‚Üí/**
     2‚Üí * MMS Maximo Sync Worker Processor
     3‚Üí *
     4‚Üí * BullMQ job processor for bidirectional synchronization with IBM Maximo.
     5‚Üí * Handles scheduled push/pull operations, conflict resolution, and polling fallback.
     6‚Üí *
     7‚Üí * Job Flow:
     8‚Üí * 1. Receive MaximoSyncJobData from queue
     9‚Üí * 2. Based on operation type:
    10‚Üí *    - push: Send pending MMS changes to Maximo
    11‚Üí *    - pull: Fetch remote changes from Maximo
    12‚Üí *    - full: Execute both push and pull
    13‚Üí *    - polling: Execute scheduled fallback pull with deduplication
    14‚Üí * 3. Handle conflicts according to resolution strategy
    15‚Üí * 4. Store sync history and update shadow records
    16‚Üí *
    17‚Üí * @see specs/007-integration.md Section 7.4
    18‚Üí */
    19‚Üí
    20‚Üíimport { logger } from '../../lib/logging/logger';
    21‚Üíimport { withSpan } from '../../lib/tracing';
    22‚Üíimport { type WorkerJobContext } from '../index';
    23‚Üíimport { type MaximoSyncJobData } from '../../lib/queue';
    24‚Üíimport {
    25‚Üí  recordMaximoSync,
    26‚Üí} from '../../lib/metrics';
    27‚Üíimport {
    28‚Üí  getMaximoSyncService,
    29‚Üí  getMaximoPollingService,
    30‚Üí  type PushResult,
    31‚Üí  type PullResult,
    32‚Üí  type ConflictResolution,
    33‚Üí} from '../../services';
    34‚Üí
    35‚Üí// =============================================================================
    36‚Üí// Worker Configuration
    37‚Üí// =============================================================================
    38‚Üí
    39‚Üíconst log = logger.child({ worker: 'maximo-sync' });
    40‚Üí
    41‚Üí// =============================================================================
    42‚Üí// Result Types
    43‚Üí// =============================================================================
    44‚Üí
    45‚Üíinterface MaximoSyncResult {
    46‚Üí  operation: 'push' | 'pull' | 'full' | 'polling';
    47‚Üí  push?: {
    48‚Üí    pushed: number;
    49‚Üí    errors: number;
    50‚Üí    details?: PushResult[];
    51‚Üí  };
    52‚Üí  pull?: {
    53‚Üí    processed: number;
    54‚Üí    updated: number;
    55‚Üí    conflicts: number;
    56‚Üí    details?: PullResult;
    57‚Üí  };
    58‚Üí  polling?: {
    59‚Üí    processed: number;
    60‚Üí    updated: number;
    61‚Üí    conflicts: number;
    62‚Üí    errors: number;
    63‚Üí    duplicatesPrevented: number;
    64‚Üí    syncMode: string;
    65‚Üí  };
    66‚Üí  durationMs: number;
    67‚Üí  success: boolean;
    68‚Üí}
    69‚Üí
    70‚Üí// =============================================================================
    71‚Üí// Job Processor
    72‚Üí// =============================================================================
    73‚Üí
    74‚Üí/**
    75‚Üí * Process Maximo sync job
    76‚Üí *
    77‚Üí * Executes bidirectional synchronization between MMS and Maximo.
    78‚Üí * Supports push (MMS‚ÜíMaximo), pull (Maximo‚ÜíMMS), or full (both) operations.
    79‚Üí */
    80‚Üíexport async function processMaximoSyncJob(
    81‚Üí  context: WorkerJobContext<MaximoSyncJobData>
    82‚Üí): Promise<MaximoSyncResult> {
    83‚Üí  return withSpan('worker.maximo_sync.process', async (span) => {
    84‚Üí    const { id, data } = context;
    85‚Üí    const { operation, pmScheduleIds, depotId, force, conflictResolution } = data;
    86‚Üí    const startTime = Date.now();
    87‚Üí
    88‚Üí    span.setAttribute('jobId', id);
    89‚Üí    span.setAttribute('operation', operation);
    90‚Üí    span.setAttribute('hasSpecificPms', !!pmScheduleIds);
    91‚Üí    span.setAttribute('depotId', depotId ?? 'all');
    92‚Üí    span.setAttribute('force', force ?? false);
    93‚Üí
    94‚Üí    log.info(
    95‚Üí      { jobId: id, operation, pmScheduleIds: pmScheduleIds?.length, depotId, force },
    96‚Üí      'Processing Maximo sync job'
    97‚Üí    );
    98‚Üí
    99‚Üí    const result: MaximoSyncResult = {
   100‚Üí      operation,
   101‚Üí      durationMs: 0,
   102‚Üí      success: true,
   103‚Üí    };
   104‚Üí
   105‚Üí    const maximoService = getMaximoSyncService();
   106‚Üí
   107‚Üí    try {
   108‚Üí      // Execute push operation
   109‚Üí      if (operation === 'push' || operation === 'full') {
   110‚Üí        await context.updateProgress({ stage: 'PUSHING', percent: 10 });
   111‚Üí        await context.log('Starting push sync (MMS ‚Üí Maximo)');
   112‚Üí
   113‚Üí        const pushResult = await executePush(
   114‚Üí          maximoService,
   115‚Üí          pmScheduleIds,
   116‚Üí          context
   117‚Üí        );
   118‚Üí
   119‚Üí        result.push = pushResult;
   120‚Üí
   121‚Üí        log.info(
   122‚Üí          { jobId: id, pushed: pushResult.pushed, errors: pushResult.errors },
   123‚Üí          'Push sync complete'
   124‚Üí        );
   125‚Üí      }
   126‚Üí
   127‚Üí      // Execute pull operation
   128‚Üí      if (operation === 'pull' || operation === 'full') {
   129‚Üí        const progressBase = operation === 'full' ? 50 : 10;
   130‚Üí        await context.updateProgress({ stage: 'PULLING', percent: progressBase });
   131‚Üí        await context.log('Starting pull sync (Maximo ‚Üí MMS)');
   132‚Üí
   133‚Üí        const pullResult = await executePull(
   134‚Üí          maximoService,
   135‚Üí          conflictResolution as ConflictResolution | undefined,
   136‚Üí          context
   137‚Üí        );
   138‚Üí
   139‚Üí        result.pull = pullResult;
   140‚Üí
   141‚Üí        log.info(
   142‚Üí          {
   143‚Üí            jobId: id,
   144‚Üí            processed: pullResult.processed,
   145‚Üí            updated: pullResult.updated,
   146‚Üí            conflicts: pullResult.conflicts,
   147‚Üí          },
   148‚Üí          'Pull sync complete'
   149‚Üí        );
   150‚Üí      }
   151‚Üí
   152‚Üí      // Execute polling operation (fallback mode with deduplication)
   153‚Üí      if (operation === 'polling') {
   154‚Üí        await context.updateProgress({ stage: 'POLLING', percent: 10 });
   155‚Üí        await context.log('Starting polling sync (Maximo ‚Üí MMS with deduplication)');
   156‚Üí
   157‚Üí        const pollingResult = await executePolling(depotId, context);
   158‚Üí
   159‚Üí        result.polling = pollingResult;
   160‚Üí
   161‚Üí        log.info(
   162‚Üí          {
   163‚Üí            jobId: id,
   164‚Üí            processed: pollingResult.processed,
   165‚Üí            updated: pollingResult.updated,
   166‚Üí            duplicatesPrevented: pollingResult.duplicatesPrevented,
   167‚Üí            syncMode: pollingResult.syncMode,
   168‚Üí          },
   169‚Üí          'Polling sync complete'
   170‚Üí        );
   171‚Üí      }
   172‚Üí
   173‚Üí      // Calculate duration
   174‚Üí      result.durationMs = Date.now() - startTime;
   175‚Üí
   176‚Üí      // Determine overall success
   177‚Üí      const pollingErrors = result.polling?.errors ?? 0;
   178‚Üí      result.success =
   179‚Üí        (result.push?.errors ?? 0) === 0 &&
   180‚Üí        (result.pull?.conflicts ?? 0) === 0 &&
   181‚Üí        pollingErrors === 0;
   182‚Üí
   183‚Üí      // Update progress: complete
   184‚Üí      await context.updateProgress({ stage: 'COMPLETE', percent: 100 });
   185‚Üí
   186‚Üí      // Log summary
   187‚Üí      const summaryParts: string[] = [];
   188‚Üí      if (result.push) summaryParts.push(`${result.push.pushed} pushed`);
   189‚Üí      if (result.pull) {
   190‚Üí        summaryParts.push(`${result.pull.updated} updated`);
   191‚Üí        summaryParts.push(`${result.pull.conflicts} conflicts`);
   192‚Üí      }
   193‚Üí      if (result.polling) {
   194‚Üí        summaryParts.push(`${result.polling.updated} polled`);
   195‚Üí        summaryParts.push(`${result.polling.duplicatesPrevented} deduplicated`);
   196‚Üí      }
   197‚Üí      summaryParts.push(`${result.durationMs}ms`);
   198‚Üí      await context.log(`Sync complete: ${summaryParts.join(', ')}`);
   199‚Üí
   200‚Üí      // Record metrics
   201‚Üí      span.setAttribute('maximo.pushed', result.push?.pushed ?? 0);
   202‚Üí      span.setAttribute('maximo.pushErrors', result.push?.errors ?? 0);
   203‚Üí      span.setAttribute('maximo.pulled', result.pull?.processed ?? 0);
   204‚Üí      span.setAttribute('maximo.updated', result.pull?.updated ?? result.polling?.updated ?? 0);
   205‚Üí      span.setAttribute('maximo.conflicts', result.pull?.conflicts ?? result.polling?.conflicts ?? 0);
   206‚Üí      span.setAttribute('maximo.pollingDuplicatesPrevented', result.polling?.duplicatesPrevented ?? 0);
   207‚Üí      span.setAttribute('maximo.durationMs', result.durationMs);
   208‚Üí      span.setAttribute('maximo.success', result.success);
   209‚Üí
   210‚Üí      // Record Prometheus metrics
   211‚Üí      const status = result.success ? 'success' : result.polling?.errors || result.pull?.conflicts ? 'partial' : 'failure';
   212‚Üí      recordMaximoSync(
   213‚Üí        operation,
   214‚Üí        status,
   215‚Üí        result.durationMs,
   216‚Üí        result.pull?.processed ?? result.polling?.processed ?? 0,
   217‚Üí        result.pull?.updated ?? result.polling?.updated ?? 0
   218‚Üí      );
   219‚Üí
   220‚Üí      log.info(
   221‚Üí        {
   222‚Üí          jobId: id,
   223‚Üí          operation,
   224‚Üí          success: result.success,
   225‚Üí          durationMs: result.durationMs,
   226‚Üí        },
   227‚Üí        'Maximo sync job complete'
   228‚Üí      );
   229‚Üí
   230‚Üí      return result;
   231‚Üí    } catch (error) {
   232‚Üí      result.durationMs = Date.now() - startTime;
   233‚Üí      result.success = false;
   234‚Üí
   235‚Üí      log.error(
   236‚Üí        { jobId: id, error, durationMs: result.durationMs },
   237‚Üí        'Maximo sync job failed'
   238‚Üí      );
   239‚Üí
   240‚Üí      throw error;
   241‚Üí    }
   242‚Üí  });
   243‚Üí}
   244‚Üí
   245‚Üí/**
   246‚Üí * Execute push operation (MMS ‚Üí Maximo)
   247‚Üí */
   248‚Üíasync function executePush(
   249‚Üí  service: ReturnType<typeof getMaximoSyncService>,
   250‚Üí  pmScheduleIds: string[] | undefined,
   251‚Üí  context: WorkerJobContext<MaximoSyncJobData>
   252‚Üí): Promise<{ pushed: number; errors: number; details?: PushResult[] }> {
   253‚Üí  // If specific PM IDs provided, push them individually
   254‚Üí  if (pmScheduleIds && pmScheduleIds.length > 0) {
   255‚Üí    const details: PushResult[] = [];
   256‚Üí    let pushed = 0;
   257‚Üí    let errors = 0;
   258‚Üí
   259‚Üí    for (let i = 0; i < pmScheduleIds.length; i++) {
   260‚Üí      const pmId = pmScheduleIds[i];
   261‚Üí      const progress = 10 + Math.floor((i / pmScheduleIds.length) * 40);
   262‚Üí      await context.updateProgress({ stage: 'PUSHING', percent: progress, current: i + 1, total: pmScheduleIds.length });
   263‚Üí
   264‚Üí      try {
   265‚Üí        const result = await service.pushToMaximo(pmId);
   266‚Üí        details.push(result);
   267‚Üí        if (result.action === 'CREATED' || result.action === 'UPDATED') {
   268‚Üí          pushed++;
   269‚Üí        } else {
   270‚Üí          errors++;
   271‚Üí        }
   272‚Üí      } catch (error) {
   273‚Üí        errors++;
   274‚Üí        log.warn({ pmScheduleId: pmId, error }, 'Failed to push PM to Maximo');
   275‚Üí      }
   276‚Üí    }
