     1‚Üí/**
     2‚Üí * MMS Queue Configuration
     3‚Üí *
     4‚Üí * BullMQ queue setup for background job processing.
     5‚Üí * All queue operations go through Redis for distributed processing.
     6‚Üí *
     7‚Üí * Queue types:
     8‚Üí * - ingestion: CSV file processing and mileage data import
     9‚Üí * - tactical_scheduler: PM scheduling within 12-week horizon
    10‚Üí * - strategic_planner: Long-term (10-year) PM planning
    11‚Üí * - optimizer: Run assignment optimization (CP-SAT)
    12‚Üí * - manhour_leveling: Workload balancing across periods
    13‚Üí * - drift_monitor: Baseline comparison and drift detection
    14‚Üí * - notification: Email and alert sending
    15‚Üí * - report: PDF/Excel report generation
    16‚Üí *
    17‚Üí * @see specs/004-backend-specification.md Section 4.8
    18‚Üí */
    19‚Üí
    20‚Üíimport { Queue, Worker, QueueEvents, type JobsOptions, type WorkerOptions } from 'bullmq';
    21‚Üí
    22‚Üí// =============================================================================
    23‚Üí// Queue Names
    24‚Üí// =============================================================================
    25‚Üí
    26‚Üíexport const QUEUE_NAMES = {
    27‚Üí  INGESTION: 'mms:ingestion',
    28‚Üí  TACTICAL_SCHEDULER: 'mms:tactical-scheduler',
    29‚Üí  STRATEGIC_PLANNER: 'mms:strategic-planner',
    30‚Üí  OPTIMIZER: 'mms:optimizer',
    31‚Üí  MANHOUR_LEVELING: 'mms:manhour-leveling',
    32‚Üí  DRIFT_MONITOR: 'mms:drift-monitor',
    33‚Üí  NOTIFICATION: 'mms:notification',
    34‚Üí  REPORT: 'mms:report',
    35‚Üí  MAXIMO_SYNC: 'mms:maximo-sync',
    36‚Üí} as const;
    37‚Üí
    38‚Üíexport type QueueName = (typeof QUEUE_NAMES)[keyof typeof QUEUE_NAMES];
    39‚Üí
    40‚Üí// =============================================================================
    41‚Üí// Redis Configuration
    42‚Üí// =============================================================================
    43‚Üí
    44‚Üífunction getRedisConfig() {
    45‚Üí  return {
    46‚Üí    host: process.env['REDIS_HOST'] ?? 'localhost',
    47‚Üí    port: parseInt(process.env['REDIS_PORT'] ?? '6379', 10),
    48‚Üí    password: process.env['REDIS_PASSWORD'],
    49‚Üí    maxRetriesPerRequest: null as null, // Required for BullMQ
    50‚Üí  };
    51‚Üí}
    52‚Üí
    53‚Üí// =============================================================================
    54‚Üí// Job Types
    55‚Üí// =============================================================================
    56‚Üí
    57‚Üíexport interface IngestionJobData {
    58‚Üí  filePath: string;
    59‚Üí  fileName: string;
    60‚Üí  fileSize: number;
    61‚Üí  uploadedBy?: string;
    62‚Üí}
    63‚Üí
    64‚Üíexport interface TacticalSchedulerJobData {
    65‚Üí  fleetId?: string;
    66‚Üí  trainIds?: string[];
    67‚Üí  horizonWeeks?: number;
    68‚Üí  dryRun?: boolean;
    69‚Üí}
    70‚Üí
    71‚Üíexport interface StrategicPlannerJobData {
    72‚Üí  fleetId?: string;
    73‚Üí  horizonYears?: number;
    74‚Üí  populationSize?: number;
    75‚Üí  generations?: number;
    76‚Üí}
    77‚Üí
    78‚Üíexport interface OptimizerJobData {
    79‚Üí  date: string;
    80‚Üí  fleetId: string;
    81‚Üí  constraints?: {
    82‚Üí    serviceRequirements?: Record<string, number>;
    83‚Üí    unavailableTrains?: string[];
    84‚Üí    preferredAssignments?: Record<string, string>;
    85‚Üí  };
    86‚Üí  timeoutMs?: number;
    87‚Üí}
    88‚Üí
    89‚Üíexport interface ManhourLevelingJobData {
    90‚Üí  depotId?: string;
    91‚Üí  periodStart: string;
    92‚Üí  periodEnd: string;
    93‚Üí  strategies?: string[];
    94‚Üí}
    95‚Üí
    96‚Üíexport interface DriftMonitorJobData {
    97‚Üí  baselineId: string;
    98‚Üí  trainIds?: string[];
    99‚Üí}
   100‚Üí
   101‚Üíexport interface NotificationJobData {
   102‚Üí  type: 'email' | 'webhook';
   103‚Üí  template: string;
   104‚Üí  recipients: string[];
   105‚Üí  data: Record<string, unknown>;
   106‚Üí  priority?: 'high' | 'normal' | 'low';
   107‚Üí}
   108‚Üí
   109‚Üíexport interface ReportJobData {
   110‚Üí  type: 'pm_schedule' | 'fleet_status' | 'drift_report' | 'tco_projection';
   111‚Üí  format: 'pdf' | 'excel';
   112‚Üí  filters?: Record<string, unknown>;
   113‚Üí  requestedBy: string;
   114‚Üí}
   115‚Üí
   116‚Üíexport interface MaximoSyncJobData {
   117‚Üí  /** Sync operation: push, pull, full (both), or polling (scheduled pull) */
   118‚Üí  operation: 'push' | 'pull' | 'full' | 'polling';
   119‚Üí  /** Optional: specific PM schedule IDs to sync (push only) */
   120‚Üí  pmScheduleIds?: string[];
   121‚Üí  /** Optional: depot ID to limit sync scope */
   122‚Üí  depotId?: string;
   123‚Üí  /** Force sync even if recently synced */
   124‚Üí  force?: boolean;
   125‚Üí  /** Conflict resolution strategy (must match ConflictResolution type from maximo-sync service) */
   126‚Üí  conflictResolution?: 'USE_MMS' | 'USE_MAXIMO';
   127‚Üí  /** Polling-specific: triggered by webhook timeout fallback */
   128‚Üí  isPollingFallback?: boolean;
   129‚Üí  /** Polling-specific: modified since timestamp for incremental queries */
   130‚Üí  modifiedSince?: string;
   131‚Üí  /** Polling-specific: enable deduplication against recent webhooks */
   132‚Üí  deduplicateWithWebhooks?: boolean;
   133‚Üí}
   134‚Üí
   135‚Üíexport type JobData =
   136‚Üí  | IngestionJobData
   137‚Üí  | TacticalSchedulerJobData
   138‚Üí  | StrategicPlannerJobData
   139‚Üí  | OptimizerJobData
   140‚Üí  | ManhourLevelingJobData
   141‚Üí  | DriftMonitorJobData
   142‚Üí  | NotificationJobData
   143‚Üí  | ReportJobData
   144‚Üí  | MaximoSyncJobData;
   145‚Üí
   146‚Üí// =============================================================================
   147‚Üí// Default Job Options
   148‚Üí// =============================================================================
   149‚Üí
   150‚Üíconst DEFAULT_JOB_OPTIONS: JobsOptions = {
   151‚Üí  attempts: 3,
   152‚Üí  backoff: {
   153‚Üí    type: 'exponential',
   154‚Üí    delay: 1000,
   155‚Üí  },
   156‚Üí  removeOnComplete: {
   157‚Üí    age: 24 * 3600,
   158‚Üí    count: 1000,
   159‚Üí  },
   160‚Üí  removeOnFail: {
   161‚Üí    age: 7 * 24 * 3600,
   162‚Üí  },
   163‚Üí};
   164‚Üí
   165‚Üí// =============================================================================
   166‚Üí// Queue Factory
   167‚Üí// =============================================================================
   168‚Üí
   169‚Üí// eslint-disable-next-line @typescript-eslint/no-explicit-any
   170‚Üíconst queues: Map<QueueName, Queue<any>> = new Map();
   171‚Üíconst queueEvents: Map<QueueName, QueueEvents> = new Map();
   172‚Üí
   173‚Üí/**
   174‚Üí * Get or create a queue instance
   175‚Üí */
   176‚Üíexport function getQueue(name: QueueName): Queue {
   177‚Üí  if (!queues.has(name)) {
   178‚Üí    const queue = new Queue(name, {
   179‚Üí      connection: getRedisConfig(),
   180‚Üí      defaultJobOptions: DEFAULT_JOB_OPTIONS,
   181‚Üí    });
   182‚Üí    queues.set(name, queue);
   183‚Üí  }
   184‚Üí  return queues.get(name)!;
   185‚Üí}
   186‚Üí
   187‚Üí/**
   188‚Üí * Get queue events for monitoring
   189‚Üí */
   190‚Üíexport function getQueueEvents(name: QueueName): QueueEvents {
   191‚Üí  if (!queueEvents.has(name)) {
   192‚Üí    const events = new QueueEvents(name, { connection: getRedisConfig() });
   193‚Üí    queueEvents.set(name, events);
   194‚Üí  }
   195‚Üí  return queueEvents.get(name)!;
   196‚Üí}
   197‚Üí
   198‚Üí// =============================================================================
   199‚Üí// Worker Factory
   200‚Üí// =============================================================================
   201‚Üí
   202‚Üíexport interface JobContext<T = unknown> {
   203‚Üí  id?: string;
   204‚Üí  name: string;
   205‚Üí  data: T;
   206‚Üí}
   207‚Üí
   208‚Üí/**
   209‚Üí * Create a worker for processing jobs
   210‚Üí */
   211‚Üíexport function createWorker<T = JobData>(
   212‚Üí  name: QueueName,
   213‚Üí  processor: (job: JobContext<T>) => Promise<unknown>,
   214‚Üí  options?: Partial<WorkerOptions>
   215‚Üí): Worker {
   216‚Üí  const workerOptions: WorkerOptions = {
   217‚Üí    connection: getRedisConfig(),
   218‚Üí    concurrency: 1,
   219‚Üí    ...options,
   220‚Üí  };
   221‚Üí
   222‚Üí  return new Worker(
   223‚Üí    name,
   224‚Üí    async (job) => {
   225‚Üí      return processor({
   226‚Üí        id: job.id,
   227‚Üí        name: job.name,
   228‚Üí        data: job.data as T,
   229‚Üí      });
   230‚Üí    },
   231‚Üí    workerOptions
   232‚Üí  );
   233‚Üí}
   234‚Üí
   235‚Üí// =============================================================================
   236‚Üí// Job Utilities
   237‚Üí// =============================================================================
   238‚Üí
   239‚Üí/**
   240‚Üí * Add a job to a queue
   241‚Üí */
   242‚Üíexport async function addJob<T = JobData>(
   243‚Üí  queueName: QueueName,
   244‚Üí  jobName: string,
   245‚Üí  data: T,
   246‚Üí  options?: Partial<JobsOptions>
   247‚Üí): Promise<{ id: string }> {
   248‚Üí  const queue = getQueue(queueName);
   249‚Üí  const job = await queue.add(jobName, data, options);
   250‚Üí  return { id: job.id! };
   251‚Üí}
   252‚Üí
   253‚Üí/**
   254‚Üí * Add multiple jobs to a queue
   255‚Üí */
   256‚Üíexport async function addBulkJobs<T = JobData>(
   257‚Üí  queueName: QueueName,
   258‚Üí  jobs: Array<{ name: string; data: T; opts?: Partial<JobsOptions> }>
   259‚Üí): Promise<Array<{ id: string }>> {
   260‚Üí  const queue = getQueue(queueName);
   261‚Üí  const results = await queue.addBulk(jobs);
   262‚Üí  return results.map((job) => ({ id: job.id! }));
   263‚Üí}
   264‚Üí
   265‚Üí/**
   266‚Üí * Get job by ID
   267‚Üí */
   268‚Üíexport async function getJob<T = JobData>(
   269‚Üí  queueName: QueueName,
   270‚Üí  jobId: string
   271‚Üí): Promise<{ id: string; data: T; status: string } | null> {
   272‚Üí  const queue = getQueue(queueName);
   273‚Üí  const job = await queue.getJob(jobId);
   274‚Üí  if (!job) return null;
   275‚Üí
   276‚Üí  const state = await job.getState();
   277‚Üí  return {
   278‚Üí    id: job.id!,
   279‚Üí    data: job.data as T,
   280‚Üí    status: state,
   281‚Üí  };
   282‚Üí}
   283‚Üí
   284‚Üí/**
   285‚Üí * Get queue statistics
   286‚Üí */
   287‚Üíexport async function getQueueStats(queueName: QueueName): Promise<{
   288‚Üí  waiting: number;
   289‚Üí  active: number;
   290‚Üí  completed: number;
   291‚Üí  failed: number;
   292‚Üí  delayed: number;
   293‚Üí}> {
   294‚Üí  const queue = getQueue(queueName);
   295‚Üí  const [waiting, active, completed, failed, delayed] = await Promise.all([
   296‚Üí    queue.getWaitingCount(),
   297‚Üí    queue.getActiveCount(),
   298‚Üí    queue.getCompletedCount(),
   299‚Üí    queue.getFailedCount(),
   300‚Üí    queue.getDelayedCount(),
   301‚Üí  ]);
   302‚Üí  return { waiting, active, completed, failed, delayed };
   303‚Üí}
   304‚Üí
   305‚Üí// =============================================================================
   306‚Üí// Cleanup
   307‚Üí// =============================================================================
   308‚Üí
   309‚Üí/**
   310‚Üí * Close all queue connections
   311‚Üí */
   312‚Üíexport async function closeAllQueues(): Promise<void> {
   313‚Üí  const closePromises: Promise<void>[] = [];
   314‚Üí
   315‚Üí  for (const queue of queues.values()) {
   316‚Üí    closePromises.push(queue.close());
   317‚Üí  }
   318‚Üí
   319‚Üí  for (const events of queueEvents.values()) {
   320‚Üí    closePromises.push(events.close());
   321‚Üí  }
   322‚Üí
   323‚Üí  await Promise.all(closePromises);
   324‚Üí  queues.clear();
   325‚Üí  queueEvents.clear();
   326‚Üí}
   327‚Üí
   328‚Üí// =============================================================================
   329‚Üí// Progress Streaming
   330‚Üí// =============================================================================
   331‚Üí
   332‚Üíexport interface JobProgress {
   333‚Üí  percent: number;
   334‚Üí  stage?: string;
   335‚Üí  message?: string;
   336‚Üí  details?: Record<string, unknown>;
   337‚Üí}
   338‚Üí
   339‚Üí/**
   340‚Üí * Stream job progress updates via callback
   341‚Üí */
   342‚Üíexport function streamJobProgress(
   343‚Üí  queueName: QueueName,
   344‚Üí  jobId: string,
   345‚Üí  onProgress: (progress: unknown) => void,
   346‚Üí  onComplete: (result: unknown) => void,
   347‚Üí  onError: (error: Error) => void
   348‚Üí): () => void {
   349‚Üí  const events = getQueueEvents(queueName);
   350‚Üí
   351‚Üí  const progressHandler = (args: { jobId: string; data: unknown }) => {
   352‚Üí    if (args.jobId === jobId) {
   353‚Üí      onProgress(args.data);
   354‚Üí    }
   355‚Üí  };
   356‚Üí
   357‚Üí  const completedHandler = (args: { jobId: string; returnvalue: unknown }) => {
   358‚Üí    if (args.jobId === jobId) {
   359‚Üí      onComplete(args.returnvalue);
   360‚Üí      cleanup();
   361‚Üí    }
   362‚Üí  };
